import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

export default function keybindConflictScopeTest(pi: ExtensionAPI) {
	pi.registerShortcut("ctrl+b", {
		description: "Test editor-scope conflict with cursorLeft",
		handler: async (ctx) => {
			ctx.ui.notify("Extension shortcut ctrl+b fired", "info");
		},
	});

	pi.registerShortcut("ctrl+p", {
		description: "Test non-editor conflict with toggleSessionPath",
		handler: async (ctx) => {
			ctx.ui.notify("Extension shortcut ctrl+p fired", "info");
		},
	});
}
